  // Each lock authored on 512x512; map its hair-mass over this head's crown/fringe (clip keeps it on
  // the silhouette). Centre (~256,200 of the lock) -> crown (~128,95); slight per-style nudges.
  const DEFAULT_LOCK_TF = "translate(12.8 5) scale(0.45)";
  const LOCK_TF = {
    sidePart: "translate(20 4) scale(0.45)",   // bias the swoop slightly across the part
    locs: "translate(8 2) scale(0.46)",         // let the long lock reach a touch lower/wider
    bob: "translate(12.8 8) scale(0.45)"        // curtain bangs sit a hair lower over the brow
  };
  function lockShade(hex, f) {
    const n = parseInt(String(hex).replace("#", ""), 16);
    if (Number.isNaN(n)) return hex;
    const c = (sh) => Math.max(0, Math.min(255, Math.round(((n >> sh) & 255) * f)));
    return `rgb(${c(16)},${c(8)},${c(0)})`;
  }
  // A freely-placed lock instance:
  //   { lock, x, y, scale, rot, lines, mirror, outline, fill, dark, shine, line }
  // x/y are 0-100 (% of the 256 head box) -> the lock's centre; null colours derive from hair.
  // mirror flips it horizontally; outline = 'none' (no outline), a hex (custom), or unset (= ink).
  const LOCK_BASE_K = 0.42; // scale=1 -> a roughly head-sized lock
  function clamp(n, lo, hi) { return Math.max(lo, Math.min(hi, n)); }
  function hasPaint(value) {
    return !!value && value !== "none" && value !== "transparent" && value !== "rgba(0,0,0,0)";
  }
