    const kNum = LOCK_BASE_K * (Number(inst.scale) || 1);
    const sx = ((inst.mirror ? -1 : 1) * kNum).toFixed(3);
    const sy = kNum.toFixed(3);
    const hx = (((Number(inst.x)) || 50) / 100 * 256).toFixed(1);
